using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF9 default: "$type".  EF8 wrote: "Discriminator".
            // Without this, EF9 cannot find existing documents and direct SQL
            // queries like  WHERE c.Discriminator = 'Product'  return nothing.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — JSON "id" value no longer includes the discriminator.
            // EF8 format: "Product|123".  EF9 default: "123".
            // Without this, every point-read and Find() against existing
            // documents will fail with a 404 because the computed id won't match.
            entity.HasDiscriminatorInJsonId();
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

