using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 3 — Synchronous I/O is no longer supported.
    // EF9 Cosmos provider throws InvalidOperationException on sync calls
    // (ToList, First, Single, SaveChanges, etc.).  Use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // in OnModelCreating (see ProductContext).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

